const UCO_CONTROLS = [
  { controlId: "UCO-AI-001", domain: "Authentication & Identity", name: "Multi-Factor Authentication for All Users", description: "Enforce MFA for all user accounts accessing systems and data.", objective: "Prevent unauthorized access through compromised credentials.", automationLevel: "full", remediationGuidance: "Enable MFA enforcement in your identity provider. Require MFA for all users, especially administrators." },
  { controlId: "UCO-AI-002", domain: "Authentication & Identity", name: "Privileged Account Controls", description: "Manage, monitor, and restrict privileged accounts with elevated permissions.", objective: "Limit blast radius of compromised administrator accounts.", automationLevel: "partial", remediationGuidance: "Audit all privileged accounts. Implement just-in-time access and require MFA for admin roles." },
  { controlId: "UCO-AI-003", domain: "Authentication & Identity", name: "Password Policy Enforcement", description: "Enforce strong password requirements including complexity, length, and rotation.", objective: "Prevent brute force and credential attacks.", automationLevel: "full", remediationGuidance: "Configure password policy in your identity provider: min 12 chars, complexity requirements, no common passwords." },
  { controlId: "UCO-AI-004", domain: "Authentication & Identity", name: "Single Sign-On / Identity Provider", description: "Centralize authentication through a managed identity provider.", objective: "Centralize access control and enable consistent policy enforcement.", automationLevel: "full", remediationGuidance: "Deploy an IdP (Okta, Azure AD, Google Workspace) and enforce SSO for all SaaS applications." },
  { controlId: "UCO-AC-001", domain: "Access Control", name: "Role-Based Access Control", description: "Implement RBAC to ensure users access only what their role requires.", objective: "Enforce least privilege across all systems and applications.", automationLevel: "partial", remediationGuidance: "Define roles with minimum necessary permissions. Review and enforce roles across all systems." },
  { controlId: "UCO-AC-002", domain: "Access Control", name: "Least Privilege Principle", description: "Grant minimum access required for job function.", objective: "Reduce attack surface from over-provisioned accounts.", automationLevel: "partial", remediationGuidance: "Audit permissions quarterly. Remove excessive access. Use just-in-time access for sensitive resources." },
  { controlId: "UCO-AC-003", domain: "Access Control", name: "Separation of Duties", description: "Ensure no single user can execute high-risk transactions alone.", objective: "Prevent fraud and errors through dual-control requirements.", automationLevel: "manual", remediationGuidance: "Identify critical actions requiring dual approval. Implement approval workflows." },
  { controlId: "UCO-AC-004", domain: "Access Control", name: "Periodic Access Reviews", description: "Regularly review and recertify user access rights.", objective: "Remove stale and inappropriate access over time.", automationLevel: "partial", remediationGuidance: "Schedule quarterly access reviews. Remove access for users who no longer need it." },
  { controlId: "UCO-AC-005", domain: "Access Control", name: "Offboarding & Deprovisioning", description: "Remove all access within 24 hours of employee departure.", objective: "Prevent ex-employee unauthorized access.", automationLevel: "partial", remediationGuidance: "Automate offboarding with HR system triggers. Audit for orphaned accounts monthly." },
  { controlId: "UCO-AL-001", domain: "Audit & Logging", name: "Audit Logging Enabled", description: "Enable comprehensive audit logs for all systems and user actions.", objective: "Detect security incidents and support forensic investigations.", automationLevel: "full", remediationGuidance: "Enable CloudTrail, audit logs on databases, and application logging. Centralize in SIEM." },
  { controlId: "UCO-AL-002", domain: "Audit & Logging", name: "Log Integrity & Retention", description: "Store logs securely with integrity protection for minimum 12 months.", objective: "Ensure logs are available and trustworthy for investigation.", automationLevel: "full", remediationGuidance: "Store logs in write-once storage (S3 with Object Lock). Retain for 12+ months." },
  { controlId: "UCO-AL-003", domain: "Audit & Logging", name: "Security Monitoring / SIEM", description: "Monitor logs continuously for security events and anomalies.", objective: "Detect threats in real-time before damage occurs.", automationLevel: "full", remediationGuidance: "Deploy SIEM (Splunk, Datadog, CloudWatch). Create alerts for key security events." },
  { controlId: "UCO-AL-004", domain: "Audit & Logging", name: "Alerting on Security Anomalies", description: "Generate real-time alerts for suspicious activity and policy violations.", objective: "Enable rapid response to security incidents.", automationLevel: "full", remediationGuidance: "Configure alerts for: failed logins, privilege escalation, unusual data access, off-hours activity." },
  { controlId: "UCO-CM-001", domain: "Configuration Management", name: "Version Control for All Code", description: "Store all application and infrastructure code in version control.", objective: "Enable change tracking, rollback, and collaborative code review.", automationLevel: "full", remediationGuidance: "Use Git for all code. Prohibit direct production deployments outside VCS." },
  { controlId: "UCO-CM-002", domain: "Configuration Management", name: "Code Review & Approval Process", description: "Require peer review and approval before merging code changes.", objective: "Catch security vulnerabilities before they reach production.", automationLevel: "full", remediationGuidance: "Enable branch protection. Require at least 1 reviewer. Enforce CODEOWNERS for sensitive files." },
  { controlId: "UCO-CM-003", domain: "Configuration Management", name: "Vulnerability Scanning (SAST/DAST)", description: "Automatically scan code and running applications for vulnerabilities.", objective: "Identify and remediate vulnerabilities before exploitation.", automationLevel: "full", remediationGuidance: "Integrate SAST (Semgrep, CodeQL) and dependency scanning in CI/CD pipelines." },
  { controlId: "UCO-CM-004", domain: "Configuration Management", name: "Dependency & Supply Chain Security", description: "Track and audit all third-party dependencies for vulnerabilities.", objective: "Prevent supply chain attacks through vulnerable dependencies.", automationLevel: "full", remediationGuidance: "Enable Dependabot or Snyk. Set SLAs for critical vulnerability patching." },
  { controlId: "UCO-CM-005", domain: "Configuration Management", name: "Infrastructure as Code", description: "Manage infrastructure configuration through version-controlled code.", objective: "Ensure consistent, auditable, and reproducible infrastructure.", automationLevel: "partial", remediationGuidance: "Use Terraform, CloudFormation, or Pulumi. Store IaC in version control with code review." },
  { controlId: "UCO-CM-006", domain: "Configuration Management", name: "Change Approval Process", description: "Require approval for all changes to production systems.", objective: "Prevent unauthorized or untested changes from causing incidents.", automationLevel: "partial", remediationGuidance: "Implement change management workflow with approval gates. Log all production changes." },
  { controlId: "UCO-DP-001", domain: "Data Protection", name: "Data Classification Policy", description: "Classify all data by sensitivity level with appropriate handling requirements.", objective: "Apply appropriate security controls based on data sensitivity.", automationLevel: "manual", remediationGuidance: "Define classification tiers (Public, Internal, Confidential, Restricted). Label data accordingly." },
  { controlId: "UCO-DP-002", domain: "Data Protection", name: "Encryption at Rest", description: "Encrypt all sensitive data stored in databases, file systems, and backups.", objective: "Protect data from disclosure in case of storage compromise.", automationLevel: "full", remediationGuidance: "Enable encryption on all databases, S3 buckets, EBS volumes. Use AES-256 minimum." },
  { controlId: "UCO-DP-003", domain: "Data Protection", name: "Encryption in Transit (TLS)", description: "Encrypt all data in transit using TLS 1.2 or higher.", objective: "Prevent interception and tampering of data in transit.", automationLevel: "full", remediationGuidance: "Enforce HTTPS everywhere. Disable TLS 1.0/1.1. Use certificate pinning for critical APIs." },
  { controlId: "UCO-DP-004", domain: "Data Protection", name: "Data Retention & Disposal", description: "Define and enforce data retention schedules and secure disposal procedures.", objective: "Minimize data exposure and ensure regulatory compliance.", automationLevel: "partial", remediationGuidance: "Define retention policy per data type. Automate deletion at end of retention period. Use secure wiping for hardware." },
  { controlId: "UCO-DP-005", domain: "Data Protection", name: "Backup & Recovery Testing", description: "Regularly backup data and test restoration procedures.", objective: "Ensure data can be recovered following loss or ransomware.", automationLevel: "partial", remediationGuidance: "Implement 3-2-1 backup strategy. Test restoration quarterly. Store backups off-site or in different region." },
  { controlId: "UCO-IR-001", domain: "Incident Response", name: "Incident Response Plan", description: "Maintain a documented incident response plan with defined roles and procedures.", objective: "Enable rapid, coordinated response to security incidents.", automationLevel: "manual", remediationGuidance: "Document IR plan covering: detection, containment, eradication, recovery, lessons learned. Test annually." },
  { controlId: "UCO-IR-002", domain: "Incident Response", name: "Incident Detection & Response", description: "Implement tools and processes to detect, triage, and respond to incidents.", objective: "Minimize time to detect and contain security incidents.", automationLevel: "partial", remediationGuidance: "Deploy EDR, SIEM alerting, and on-call procedures. Define severity tiers and response SLAs." },
  { controlId: "UCO-IR-003", domain: "Incident Response", name: "Security Incident Reporting", description: "Define processes for reporting incidents to regulators and affected parties.", objective: "Meet regulatory notification requirements and maintain trust.", automationLevel: "manual", remediationGuidance: "Document breach notification procedures per regulation (72 hours GDPR, FedRAMP 1 hour). Test annually." },
  { controlId: "UCO-IR-004", domain: "Incident Response", name: "Post-Incident Review", description: "Conduct blameless post-mortems after security incidents.", objective: "Learn from incidents to prevent recurrence.", automationLevel: "manual", remediationGuidance: "Conduct PIR within 5 business days. Document timeline, impact, root cause, remediation." },
  { controlId: "UCO-RM-001", domain: "Risk Management", name: "Risk Assessment Process", description: "Conduct regular formal risk assessments across the organization.", objective: "Identify, prioritize, and address security risks proactively.", automationLevel: "manual", remediationGuidance: "Conduct annual risk assessment. Maintain risk register. Review quarterly or after major changes." },
  { controlId: "UCO-RM-002", domain: "Risk Management", name: "Vendor Risk Management", description: "Assess and monitor security posture of third-party vendors.", objective: "Prevent supply chain and vendor-introduced risk.", automationLevel: "partial", remediationGuidance: "Tier vendors by data access and criticality. Complete security questionnaires. Include security in contracts." },
  { controlId: "UCO-RM-003", domain: "Risk Management", name: "Business Continuity Planning", description: "Maintain tested plans for continuing operations during disruptions.", objective: "Minimize downtime and data loss during incidents or disasters.", automationLevel: "manual", remediationGuidance: "Document BCP/DR plans. Define RTOs and RPOs. Test failover annually." },
  { controlId: "UCO-RM-004", domain: "Risk Management", name: "Penetration Testing", description: "Conduct regular third-party penetration tests of systems and applications.", objective: "Identify vulnerabilities before attackers do.", automationLevel: "manual", remediationGuidance: "Conduct annual pentest minimum. Critical systems quarterly. Remediate critical/high within 30 days." },
  { controlId: "UCO-ST-001", domain: "Security Training", name: "Security Awareness Training", description: "Provide annual security awareness training for all employees.", objective: "Reduce human error as a security risk vector.", automationLevel: "partial", remediationGuidance: "Enroll all employees in annual training. Include phishing simulations. Track completion." },
  { controlId: "UCO-ST-002", domain: "Security Training", name: "Role-Specific Security Training", description: "Provide additional security training for high-risk roles (devs, admins, finance).", objective: "Ensure high-risk roles have role-appropriate security skills.", automationLevel: "partial", remediationGuidance: "Identify high-risk roles. Provide targeted training (secure coding for devs, social engineering for finance)." },
  { controlId: "UCO-NS-001", domain: "Network Security", name: "Network Segmentation", description: "Segment networks to isolate sensitive systems and limit lateral movement.", objective: "Contain breaches and protect crown jewel systems.", automationLevel: "partial", remediationGuidance: "Implement VPCs, subnets, and security groups. Isolate production from dev/test environments." },
  { controlId: "UCO-NS-002", domain: "Network Security", name: "Firewall & Perimeter Controls", description: "Deploy and maintain firewall rules restricting unauthorized network access.", objective: "Prevent unauthorized network access to internal systems.", automationLevel: "full", remediationGuidance: "Audit firewall rules quarterly. Deny by default. Remove unused rules. Log denied traffic." },
  { controlId: "UCO-NS-003", domain: "Network Security", name: "Intrusion Detection (IDS/IPS)", description: "Deploy intrusion detection/prevention systems to identify malicious activity.", objective: "Detect and block network-based attacks in real-time.", automationLevel: "full", remediationGuidance: "Deploy IDS/IPS at network perimeter and between segments. Configure alerting for anomalies." },
  { controlId: "UCO-NS-004", domain: "Network Security", name: "Secure Remote Access (VPN/Zero Trust)", description: "Require VPN or Zero Trust access for remote connections to internal systems.", objective: "Secure remote access and prevent unauthorized entry.", automationLevel: "full", remediationGuidance: "Require VPN or Zero Trust (BeyondCorp, Cloudflare Access) for all remote access. Disable direct SSH." },
  { controlId: "UCO-VM-001", domain: "Vulnerability Management", name: "Vulnerability Management Program", description: "Maintain a formal program for identifying and remediating vulnerabilities.", objective: "Systematically reduce exploitable vulnerabilities across the environment.", automationLevel: "partial", remediationGuidance: "Define vulnerability SLAs: critical 24h, high 7d, medium 30d, low 90d. Track to closure." },
  { controlId: "UCO-VM-002", domain: "Vulnerability Management", name: "Patch Management", description: "Apply security patches to all systems within defined SLA windows.", objective: "Prevent exploitation of known vulnerabilities.", automationLevel: "partial", remediationGuidance: "Automate patching where possible. Track patch compliance. Emergency patch process for critical CVEs." },
  { controlId: "UCO-VM-003", domain: "Vulnerability Management", name: "Container & Image Security", description: "Scan container images for vulnerabilities before deployment.", objective: "Prevent known vulnerabilities from reaching production in containers.", automationLevel: "full", remediationGuidance: "Integrate container scanning in CI/CD. Use trusted base images. Run as non-root. No privileged containers." },
  // Physical Security domain
  { controlId: "UCO-PS-001", domain: "Physical Security", name: "Physical Access Controls", description: "Restrict and monitor physical access to facilities, data centers, and sensitive areas using badge/keycard systems, biometrics, and CCTV.", objective: "Prevent unauthorized physical access to systems and data storage.", automationLevel: "partial", remediationGuidance: "Deploy badge-based access control. Install CCTV at entry points. Review access logs quarterly. Implement mantrap for server rooms." },
  { controlId: "UCO-PS-002", domain: "Physical Security", name: "Visitor Management", description: "Maintain a visitor log, require escort for all visitors in secure areas, and issue temporary badges.", objective: "Prevent unauthorized access by visitors to sensitive areas.", automationLevel: "manual", remediationGuidance: "Implement visitor sign-in system. Require photo ID. Issue time-limited badges. Enforce escort policy throughout facility." },
  { controlId: "UCO-PS-003", domain: "Physical Security", name: "Clean Desk & Clear Screen Policy", description: "Require locking workstations when unattended and securing physical documents. Auto-lock policy enforced.", objective: "Prevent unauthorized access to information left on screens or desks.", automationLevel: "partial", remediationGuidance: "Configure screen lock after 5-minute idle. Train employees on clean desk. Conduct periodic walkthroughs. Shred sensitive documents." },
  { controlId: "UCO-PS-004", domain: "Physical Security", name: "Media & Equipment Disposal", description: "Securely wipe, shred, or physically destroy storage media and hardware prior to disposal or reuse.", objective: "Prevent data recovery from decommissioned hardware and storage media.", automationLevel: "manual", remediationGuidance: "Use NIST 800-88 media sanitization. Maintain chain-of-custody records. Use certified destruction vendor. Verify destruction certificates." },
  { controlId: "UCO-PS-005", domain: "Physical Security", name: "Data Center & Server Room Security", description: "Restrict access to data centers and server rooms to authorized personnel only, with environmental controls (power, cooling, fire suppression).", objective: "Protect physical infrastructure hosting sensitive systems from unauthorized access and environmental threats.", automationLevel: "partial", remediationGuidance: "Separate server room from general office. Deploy UPS and backup power. Monitor temperature and humidity. Maintain access roster." },
  // Asset Management domain
  { controlId: "UCO-AM-001", domain: "Asset Management", name: "Hardware Asset Inventory", description: "Maintain an accurate, up-to-date inventory of all hardware assets including laptops, servers, and network devices.", objective: "Ensure all hardware is known, tracked, and managed throughout its lifecycle.", automationLevel: "partial", remediationGuidance: "Deploy MDM and network scanning tools. Maintain CMDB with serial numbers and owners. Review quarterly. Tag all physical assets." },
  { controlId: "UCO-AM-002", domain: "Asset Management", name: "Software Asset Inventory & License Management", description: "Track all software installed across the organization including SaaS applications, licenses, and version status.", objective: "Prevent unauthorized software use and ensure license compliance.", automationLevel: "partial", remediationGuidance: "Deploy software inventory tools. Maintain SaaS catalog via SSO. Review unused licenses quarterly. Terminate licenses on offboarding." },
  { controlId: "UCO-AM-003", domain: "Asset Management", name: "Asset Lifecycle Management", description: "Define and enforce asset management procedures from procurement through secure disposal.", objective: "Maintain security controls throughout the entire asset lifecycle.", automationLevel: "manual", remediationGuidance: "Document asset lifecycle policy. Require security review at procurement. Conduct secure disposal per UCO-PS-004. Track asset owner changes." },
  { controlId: "UCO-AM-004", domain: "Asset Management", name: "Unauthorized Software Prevention", description: "Prevent installation and execution of unauthorized software through allowlisting and MDM policies.", objective: "Reduce attack surface from unapproved, potentially malicious software.", automationLevel: "full", remediationGuidance: "Implement application allowlisting (WDAC, Jamf). Remove admin rights from standard users. Block unapproved software via MDM policy." },
  // Endpoint Security domain
  { controlId: "UCO-EP-001", domain: "Endpoint Security", name: "Endpoint Detection & Response (EDR)", description: "Deploy EDR agents on all endpoints to detect, investigate, and respond to malicious activity in real-time.", objective: "Detect and contain endpoint-based threats before they spread.", automationLevel: "full", remediationGuidance: "Deploy CrowdStrike, SentinelOne, or equivalent. Achieve >=95% coverage. Enable automatic quarantine for critical alerts. Review daily." },
  { controlId: "UCO-EP-002", domain: "Endpoint Security", name: "Full Disk Encryption", description: "Enable full disk encryption on all laptops, workstations, and mobile devices using BitLocker, FileVault, or equivalent.", objective: "Protect data on lost or stolen devices from unauthorized access.", automationLevel: "full", remediationGuidance: "Enforce FileVault (macOS) and BitLocker (Windows) via MDM. Store recovery keys in escrow. Verify 100% compliance in MDM dashboard." },
  { controlId: "UCO-EP-003", domain: "Endpoint Security", name: "Mobile Device Management (MDM)", description: "Enroll all corporate-issued and BYOD devices in MDM to enforce security policies.", objective: "Ensure consistent security policies across all devices accessing corporate data.", automationLevel: "full", remediationGuidance: "Deploy Jamf (macOS/iOS) or Intune (Windows). Require MDM enrollment before accessing corporate resources. Enforce compliant device checks." },
  { controlId: "UCO-EP-004", domain: "Endpoint Security", name: "Removable Media Controls", description: "Control use of USB drives and removable media through technical policies and monitoring.", objective: "Prevent data exfiltration and malware introduction via removable media.", automationLevel: "full", remediationGuidance: "Block unauthorized USB via MDM policy. Log removable media usage. Allow encrypted USB only. Train employees on risks." },
  // Application Security domain
  { controlId: "UCO-AS-001", domain: "Application Security", name: "OWASP Top 10 Remediation Program", description: "Test and remediate web applications against the OWASP Top 10 vulnerabilities on a defined schedule.", objective: "Eliminate the most critical and prevalent web application vulnerabilities.", automationLevel: "partial", remediationGuidance: "Run DAST scans against all web apps annually. Integrate OWASP Top 10 checks into security reviews. Track and remediate critical findings within 30 days." },
  { controlId: "UCO-AS-002", domain: "Application Security", name: "Web Application Firewall (WAF)", description: "Deploy a WAF in front of all internet-facing web applications to block common attack patterns.", objective: "Prevent exploitation of web application vulnerabilities including SQLi, XSS, and OWASP Top 10.", automationLevel: "full", remediationGuidance: "Deploy WAF (Cloudflare, AWS WAF, Imperva). Enable managed rulesets. Run in block mode. Review blocked requests weekly. Tune false positive rules." },
  { controlId: "UCO-AS-003", domain: "Application Security", name: "API Security Controls", description: "Enforce authentication, authorization, rate limiting, and input validation on all internal and external APIs.", objective: "Prevent API abuse, unauthorized data access, and injection attacks.", automationLevel: "partial", remediationGuidance: "Require OAuth 2.0/API keys for all APIs. Implement rate limiting. Validate all inputs. Maintain API inventory. Scan APIs with DAST tools." },
  { controlId: "UCO-AS-004", domain: "Application Security", name: "Secrets Detection in Code", description: "Detect and prevent credentials, API keys, and secrets from being committed to source code repositories.", objective: "Prevent credential exposure through accidental code commits.", automationLevel: "full", remediationGuidance: "Enable GitHub secret scanning or add pre-commit hooks (git-secrets, truffleHog). Scan all repos for historical leaks. Rotate any exposed credentials immediately." },
  // Privacy Controls domain
  { controlId: "UCO-PR-001", domain: "Privacy Controls", name: "Privacy Impact Assessment (DPIA)", description: "Conduct Data Protection Impact Assessments before launching new data processing activities or high-risk systems.", objective: "Identify and mitigate privacy risks before new processing activities begin.", automationLevel: "manual", remediationGuidance: "Document DPIA process. Complete DPIAs for new products, systems, or vendors. Keep records of DPIAs completed. Review when processing changes." },
  { controlId: "UCO-PR-002", domain: "Privacy Controls", name: "Consent Management", description: "Implement mechanisms for collecting, recording, and honoring user consent for data processing and cookies.", objective: "Comply with GDPR, CCPA, and similar regulations requiring informed, explicit consent.", automationLevel: "partial", remediationGuidance: "Deploy consent management platform (OneTrust, Cookiebot). Implement granular cookie consent. Maintain consent records. Allow easy opt-out." },
  { controlId: "UCO-PR-003", domain: "Privacy Controls", name: "Data Subject Rights Process", description: "Implement processes to handle data subject requests (access, deletion, correction, portability) within regulatory timeframes.", objective: "Comply with GDPR, CCPA, and PIPEDA data subject rights requirements.", automationLevel: "partial", remediationGuidance: "Document DSR handling procedures. Respond within 30 days (GDPR: 1 month). Log all requests. Implement automated deletion workflows where possible." },
  { controlId: "UCO-PR-004", domain: "Privacy Controls", name: "Data Processing Agreements (DPA)", description: "Execute Data Processing Agreements with all vendors and sub-processors who handle personal data.", objective: "Ensure contractual protections for personal data processed by third parties.", automationLevel: "manual", remediationGuidance: "Identify all data processors. Execute GDPR-compliant DPAs. Review annually. Terminate vendor relationships where DPA cannot be obtained." },
  // Cryptography domain
  { controlId: "UCO-CR-001", domain: "Cryptography", name: "Cryptographic Key Management Lifecycle", description: "Define and enforce procedures for key generation, distribution, storage, rotation, and revocation.", objective: "Ensure cryptographic keys are properly managed throughout their lifecycle.", automationLevel: "partial", remediationGuidance: "Document key management policy. Rotate encryption keys annually. Store keys in HSM or KMS. Separate key custodians from key users. Log all key operations." },
  { controlId: "UCO-CR-002", domain: "Cryptography", name: "Certificate Management & Rotation", description: "Maintain an inventory of TLS/SSL certificates and automate renewal before expiration.", objective: "Prevent service outages and security failures from expired certificates.", automationLevel: "full", remediationGuidance: "Inventory all certificates. Automate renewal (Let's Encrypt, ACM). Alert 60 days before expiry. Monitor certificate transparency logs. No wildcard certs for production." },
  { controlId: "UCO-CR-003", domain: "Cryptography", name: "Approved Cryptographic Algorithm Standards", description: "Enforce use of approved cryptographic algorithms (AES-256, TLS 1.2+, RSA-2048+) and prohibit weak algorithms (MD5, SHA-1, DES, RC4).", objective: "Prevent use of deprecated algorithms that can be broken by adversaries.", automationLevel: "partial", remediationGuidance: "Audit all systems for deprecated crypto. Disable TLS 1.0/1.1. Enforce TLS 1.2+ minimum. Replace MD5/SHA-1 hashing. Use AES-256 for symmetric encryption." },
  { controlId: "UCO-CR-004", domain: "Cryptography", name: "Hardware Security Module (HSM) Usage", description: "Use HSMs or cloud KMS services for protecting root keys and performing critical cryptographic operations.", objective: "Prevent extraction of root cryptographic keys through software-only attacks.", automationLevel: "full", remediationGuidance: "Use AWS KMS, Azure Key Vault, or dedicated HSM for key storage. Never store root keys in application code or config files. Use HSM for code signing." },
  // Additional controls within existing domains
  { controlId: "UCO-DP-006", domain: "Data Protection", name: "Data Loss Prevention (DLP)", description: "Deploy DLP tools and policies to detect and prevent unauthorized transmission of sensitive data outside the organization.", objective: "Prevent accidental or malicious exfiltration of sensitive data.", automationLevel: "full", remediationGuidance: "Deploy DLP solution (Netskope, Forcepoint, Microsoft Purview). Define sensitive data patterns. Monitor email, cloud uploads, and USB. Alert and block on policy violations." },
  { controlId: "UCO-IR-005", domain: "Incident Response", name: "Threat Intelligence Program", description: "Subscribe to and integrate cyber threat intelligence feeds to proactively identify indicators of compromise (IOCs).", objective: "Enable proactive detection of threats targeting the organization's industry.", automationLevel: "partial", remediationGuidance: "Subscribe to ISAC feeds relevant to your industry. Integrate IOCs into SIEM. Share threat intel with sector peers. Review and act on intelligence weekly." },
  { controlId: "UCO-AC-006", domain: "Access Control", name: "Just-In-Time (JIT) Access Provisioning", description: "Grant privileged access only when needed for a specific task, with automatic expiration after the task is complete.", objective: "Eliminate standing privileged access that increases the blast radius of credential compromise.", automationLevel: "partial", remediationGuidance: "Implement JIT access for all privileged roles (cloud, servers, databases). Use PIM (Azure AD PIM, AWS IAM Temporary). Set maximum session durations." },
  { controlId: "UCO-NS-005", domain: "Network Security", name: "DDoS Protection", description: "Deploy DDoS scrubbing and traffic filtering to maintain availability of internet-facing services during volumetric attacks.", objective: "Maintain service availability during distributed denial-of-service attacks.", automationLevel: "full", remediationGuidance: "Enable CDN-level DDoS protection (Cloudflare, AWS Shield, Azure DDoS). Test protection annually. Define escalation runbook for DDoS incidents." },
  { controlId: "UCO-CM-007", domain: "Configuration Management", name: "Secrets Management", description: "Centralize storage and access of secrets, API keys, and credentials in a secrets management vault.", objective: "Prevent credential sprawl and enable automatic rotation of secrets.", automationLevel: "full", remediationGuidance: "Deploy HashiCorp Vault, AWS Secrets Manager, or Azure Key Vault. Migrate hardcoded secrets. Implement dynamic secrets where possible. Audit access logs." },
];

